import{_ as a,C as o,o as r,c as i,ag as t,E as s}from"./chunks/framework.DLWhSH9p.js";const f=JSON.parse('{"title":"Channels","description":"","frontmatter":{},"headers":[],"relativePath":"guide/channels.md","filePath":"guide/channels.md"}'),l={name:"guide/channels.md"};function h(c,e,d,g,u,p){const n=o("SchemeImage");return r(),i("div",null,[e[0]||(e[0]=t('<h1 id="channels" tabindex="-1">Channels <a class="header-anchor" href="#channels" aria-label="Permalink to &quot;Channels&quot;">​</a></h1><p>Channels are the top-level organizer in CRAFT. Each channel has its own character personality, topics, voice settings, and content library.</p><h2 id="creating-a-channel" tabindex="-1">Creating a channel <a class="header-anchor" href="#creating-a-channel" aria-label="Permalink to &quot;Creating a channel&quot;">​</a></h2><ol><li>Click the <strong>channel pill</strong> in the top chrome (left side, next to the logo) to open the dropdown.</li><li>Click <strong>+ New channel</strong> at the bottom.</li><li>Enter a <strong>Channel name</strong> and optional <strong>Character name</strong>.</li><li>Click <strong>Create</strong>.</li></ol>',4)),s(n,{name:"create-channel",alt:"Create Channel dialog inside the channel pill dropdown"}),e[1]||(e[1]=t('<p>You&#39;ll land in the new channel&#39;s Settings so you can configure character, voice, and topics.</p><h2 id="channel-settings" tabindex="-1">Channel settings <a class="header-anchor" href="#channel-settings" aria-label="Permalink to &quot;Channel settings&quot;">​</a></h2><p>Open them from the top chrome — either the <strong>Settings</strong> link in the right-rail (only visible when a channel is selected) or the channel-pill dropdown → <strong>Channel settings</strong>. See the full <a href="/guide/settings.html">Settings guide</a>.</p><h3 id="character" tabindex="-1">Character <a class="header-anchor" href="#character" aria-label="Permalink to &quot;Character&quot;">​</a></h3><ul><li><strong>Name</strong> — your character&#39;s display name</li><li><strong>Description</strong> — personality, tone, speaking style. This is fed to the AI for all content generation.</li><li><strong>Topics</strong> — content themes (e.g., &quot;cloud computing&quot;, &quot;DevOps&quot;, &quot;terraform&quot;). Used as default search hints in Discover.</li><li><strong>Tags</strong> — organizational labels for your ideas and scripts</li></ul><div class="tip custom-block"><p class="custom-block-title">AI Character Creator</p><p>Click <strong>Create Character</strong> in Settings to have AI generate a full character description from a few inputs: tone, audience, inspiration, and quirks.</p></div><h3 id="voice" tabindex="-1">Voice <a class="header-anchor" href="#voice" aria-label="Permalink to &quot;Voice&quot;">​</a></h3><p>Configure a default TTS voice for audio generation:</p><ul><li><strong>Service</strong> — Edge TTS (free), ElevenLabs, or OpenAI</li><li><strong>Voice</strong> — cascading filters by language, gender, then specific voice</li><li><strong>Test</strong> — preview the voice before saving</li></ul><h3 id="analytics" tabindex="-1">Analytics <a class="header-anchor" href="#analytics" aria-label="Permalink to &quot;Analytics&quot;">​</a></h3><ul><li><strong>RPM</strong> — Revenue Per Mille (per 1,000 views). Used for earnings estimates in Discover.</li><li><strong>Niche Presets</strong> — quick-select RPM values (Gaming $3, Tech $6, Finance $10, etc.)</li></ul><h3 id="claude-md" tabindex="-1">CLAUDE.md <a class="header-anchor" href="#claude-md" aria-label="Permalink to &quot;CLAUDE.md&quot;">​</a></h3><p>The AI Context editor lets you view and edit the CLAUDE.md file that shapes Claude&#39;s responses for this channel. In <strong>Character</strong> mode, it&#39;s auto-generated from your settings. In <strong>Raw</strong> mode, you can write custom instructions.</p><h2 id="switching-channels" tabindex="-1">Switching channels <a class="header-anchor" href="#switching-channels" aria-label="Permalink to &quot;Switching channels&quot;">​</a></h2><p>The top chrome gives you three ways to switch:</p><ul><li><strong>Peer avatars</strong> — the next few channels sit as small avatars next to the channel pill. One click to switch.</li><li><strong>Channel pill dropdown</strong> — shows every channel you own with subs/character, click to select.</li><li><strong>⌘K command palette</strong> — type a channel name, hit enter. See <a href="/guide/command-palette.html">Top chrome &amp; ⌘K</a>.</li></ul><h2 id="channel-ownership" tabindex="-1">Channel ownership <a class="header-anchor" href="#channel-ownership" aria-label="Permalink to &quot;Channel ownership&quot;">​</a></h2><p>Each channel is owned by the user who created it. What you can see and edit depends on your <a href="/guide/auth.html">role</a>:</p><table tabindex="0"><thead><tr><th>Role</th><th>See own channels</th><th>See others&#39;</th><th>Edit others&#39;</th></tr></thead><tbody><tr><td><strong>Admin</strong></td><td>Yes</td><td>Yes</td><td>Yes</td></tr><tr><td><strong>Editor</strong></td><td>Yes</td><td>Yes (read-only)</td><td>No</td></tr><tr><td><strong>Standard</strong></td><td>Yes</td><td>No</td><td>No</td></tr></tbody></table><p>When you create a channel it&#39;s automatically assigned to you. Your username and role live under the avatar menu in the top-right of the chrome.</p><h2 id="multiple-channels" tabindex="-1">Multiple Channels <a class="header-anchor" href="#multiple-channels" aria-label="Permalink to &quot;Multiple Channels&quot;">​</a></h2><p>You can create as many channels as you need — one per YouTube channel, or separate ones for different content series.</p>',22))])}const C=a(l,[["render",h]]);export{f as __pageData,C as default};
